#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Channel-1 revival + async-ramp tame, NON-BLOCKING (exit-0-safe). All systemctl calls
use --no-block + short subprocess timeouts so a long importer can never wedge the applier."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
def sh(c,t=12):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t); return (r.stdout+r.stderr).strip()
    except Exception as e: return "TO/ERR"
out={"kind":"harden","ver":2,"ts":int(time.time())}
try:
    units=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}'").split()
    nrd=[u for u in units if 'nrd' in u.lower()]
    czds=[u for u in units if 'czds' in u.lower()]
    ramp=[u for u in units if 'ramp' in u.lower()]
    out["found"]={"nrd":nrd,"czds":czds,"ramp":ramp}
    rev=[]
    for u in nrd+czds:
        if u.endswith('.timer'):
            rev.append(u+":enable="+sh("systemctl enable %s 2>&1 | tail -1; systemctl start --no-block %s 2>&1; systemctl is-enabled %s"%(u,u,u)))
        elif u.endswith('.service'):
            sh("systemctl start --no-block %s 2>&1"%u)  # fire one-shot backfill, non-blocking
    out["channel1_revived"]=rev
    tamed=[]
    for u in ramp:
        tamed.append(u+":"+sh("systemctl stop --no-block %s 2>&1; systemctl disable %s 2>&1 | tail -1"%(u,u)))
    out["async_ramp_tamed"]=tamed
    out["nrd_timers"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE 'nrd|czds'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br=env.get("STATUS_BRANCH","main"); api="https://api.github.com"; path="status/hetzner/harden.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"harden2","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
